  ('public-health-specialist-moex-00206', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關「巧推（nudge）」理論的敘述何者正確？', '["巧推理論的理念也被稱做是「自由家長制（libertarianpaternalism）」", "其內涵在限制個體的選擇或顯著改變經濟誘因的情況下，來影響人們的行為", "在不同的族群或場域下，運用相同的巧推策略皆可以帶來類似的效果", "巧推理論的重點在讓個人保有自由選擇的權利，因此其策略不涉及「提醒」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
